def story_bracket(stories):
    if stories <= 1:
        return "1 story"
    elif stories == 2:
        return "2 stories"
    elif 3 <= stories <= 5:
        return "3-5 stories"
    elif 6 <= stories <= 10:
        return "6-10 stories"
    else:
        return "11+ stories"

def age_bracket(age):
    if age <= 20:
        return "0-20 yrs"
    elif age <= 40:
        return "21-40 yrs"
    elif age <= 60:
        return "41-60 yrs"
    elif age <= 80:
        return "61-80 yrs"
    else:
        return "81+ yrs"

df = arg.copy()

df["STORY BRACKET"] = df["AVERAGE STORIES"].apply(story_bracket)
df["AGE BRACKET"] = df["AVERAGE BUILDING AGE"].apply(age_bracket)
return df

{
